    int len = (int)c;
    for (int tr = 0; tr < len; tr++) { cout << c[tr] << ","; }
    cout << endl << "Len = " << len << endl;
    cout << "Ascii codes: ";
    for (int tr = 0; tr < 10; tr++) {
        cout << c(tr) << ",";
    }
    return 0;
}
```

